headStyles:
body {
  background: var(--dark-bg);
}
.legal-hero {
  padding: calc(var(--nav-height) + 3rem) 2rem 2rem;
  text-align: center;
}
.legal-hero h1 {
  font-family: "Montserrat", sans-serif;
  font-size: clamp(1.8rem, 4vw, 2.8rem);
  font-weight: 700;
  color: var(--text-white);
  margin-bottom: 0.5rem;
}
.legal-hero .hero-divider {
  width: 80px;
  height: 4px;
  background: var(--pride-gradient);
  margin: 1.5rem auto;
  border-radius: 2px;
}
.legal-hero p {
  font-family: "Roboto Slab", serif;
  color: var(--text-light);
  font-size: 1rem;
}
.legal-body {
  max-width: 800px;
  margin: 0 auto;
  padding: 2rem;
}
.legal-body h2 {
  font-family: "Montserrat", sans-serif;
  font-size: 1.3rem;
  font-weight: 700;
  color: var(--text-white);
  margin-top: 2.5rem;
  margin-bottom: 0.75rem;
}
.legal-body p,
.legal-body li {
  font-family: "Roboto Slab", serif;
  color: var(--text-light);
  font-size: 0.95rem;
  line-height: 1.8;
  margin-bottom: 1rem;
}
.legal-body ul {
  padding-left: 1.5rem;
  margin-bottom: 1rem;
}
.legal-body li {
  margin-bottom: 0.5rem;
}
.legal-body a {
  color: var(--color-light-blue, #60a5fa);
  text-decoration: underline;
}
